def gen(rng, size):
    n = rng.randint(2, max(2, size))
    base = sorted(rng.randint(-1000, 1000) for _ in range(n))
    if rng.random() < 0.5:
        base.reverse()
    for _ in range(rng.randint(0, 3)):
        i = rng.randrange(n); j = rng.randrange(n)
        base[i], base[j] = base[j], base[i]
    return [base]

