var isMonotonic = function(nums) {
    let up = false, down = false;
    for (let i = 1; i < nums.length; i++) {
        if (nums[i] > nums[i - 1]) up = true;
        else if (nums[i] < nums[i - 1]) down = true;
    }
    return !(up && down);
};
